#include<bits/stdc++.h>
using namespace std;
typedef unsigned long long u64;

const int BASE = 13331;

u64 p[1000006], h[1000006];

u64 get(int l, int r)
{
    return h[r] - h[l - 1] * p[r - l + 1];
}

int main()
{
    int l;
    cin >> l;
    string s;
    cin >> s;
    s = "#" + s;
    p[0] = 1;
    for(int i = 1; i <= l; i++){
        p[i] = p[i - 1] * BASE;
        h[i] = h[i - 1] * BASE + s[i];
    }
    for(int i = 1; i <= l; i++)
        if(get(1, l - i) == get(i + 1, l))
            cout << i << endl, exit(0);
}
